import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useParams, useNavigate } from "react-router-dom";

function Checkout()
{

    const navigate = useNavigate();
    const { category, slug } = useParams();

    // Redirect to home if not authenticated
    if (!localStorage.getItem('auth_token'))
    {
        navigate('/');
        Swal.fire("Warning", "Login to access Cart Page", "error");
    }

    const [cart, setCart] = useState([]);
    const [loading, setLoading] = useState(true);
    var totalCartPrice = 0;


    useEffect(() =>
    {
        let isMounted = true;

        axios.get(`/api/cart`).then(res =>
        {
            if (isMounted)
            {
                if (res.data.status === 200)
                {
                    setCart(res.data.cart);

                } else if (res.data.status === 401)
                {
                    navigate('/');
                    Swal.fire("Warning", res.data.message, "error");
                }
                setLoading(false);
            }
        }).catch(err =>
        {
            if (isMounted)
            {
                console.error("Error fetching product details:", err);
                Swal.fire("Error", "Could not fetch data. Please try again later.", "error");
                setLoading(false);
            }
        });

        return () =>
        {
            isMounted = false;
        };
    }, [category, slug, navigate]);

    if (loading)
    {
        return <h4>Loading Checkout...</h4>;
    }

    return (
        <div>
            <div className="py-3 bg-warning">
                <div className="container">
                    <h6>Home / Checkout</h6>
                </div>
            </div>

            <div className="py-4">
                <div className="container">
                    <div className="row">

                        <div className="col-md-7">
                            <div className="card">
                                <div className="card-header">
                                    <h4>Billing Details</h4>
                                </div>
                                <div className="card-body">

                                    <div className="row">

                                        <div className="col-md-6">
                                            <div className="mb-3">
                                                <label className="form-label">First Name</label>
                                                <input type="text" name="firstname" className="form-control" />
                                            </div>
                                        </div>

                                        <div className="col-md-6">
                                            <div className="mb-3">
                                                <label className="form-label">Last Name</label>
                                                <input type="text" name="lastname" className="form-control" />
                                            </div>
                                        </div>

                                        <div className="col-md-12">
                                            <div className="mb-3">
                                                <label className="form-label">Email Address</label>
                                                <input type="text" name="email" className="form-control" />
                                            </div>
                                        </div>

                                        <div className="col-md-12">
                                            <div className="mb-3">
                                                <label className="form-label">Phone Number</label>
                                                <input type="text" name="phone" className="form-control" />
                                            </div>
                                        </div>

                                        <div className="col-md-12">
                                            <div className="mb-3">
                                                <label className="form-label">Address</label>
                                                <textarea name="address" className="form-control" rows="2"></textarea>
                                            </div>
                                        </div>

                                        <div className="col-md-12">
                                            <div className="mb-3">
                                                <label className="form-label">City</label>
                                                <input type="text" name="city" className="form-control" />
                                            </div>
                                        </div>

                                        <div className="col-md-12">
                                            <div className="mb-3">
                                                <label className="form-label">Country</label>
                                                <input type="text" name="state" className="form-control" />
                                            </div>
                                        </div>

                                        {/* Add place order */}
                                        <div className="col-md-12">
                                            <div className="mb-3">
                                                <button type="button" className="btn btn-primary">Place Order</button>
                                            </div>
                                        </div>

                                    </div>


                                </div>
                            </div>
                        </div>

                        <div className="col-md-5">
                            <table className="table table-border">
                                <thread>
                                    <tr>
                                        <th width="50%">Product</th>
                                        <th>Price</th>
                                        <th>Qty</th>
                                        <th>Total</th>
                                    </tr>
                                </thread>

                                <tbody>

                                    {cart.map((item, index) =>
                                    {
                                        totalCartPrice += item.product.selling_price * item.product_qty;
                                        return (
                                            <tr key={index}>
                                                <td>{item.product.name}}</td>
                                                <td>$100</td>
                                                <td>1</td>
                                                <td>$100</td>
                                            </tr>
                                        )
                                    })}

                                    <tr>
                                        <td colSpan="3" className="text-end">Grand Total</td>
                                        <td colSpan="2" className="text-end">${totalCartPrice}</td>
                                    </tr>

                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div >
    );
}
export default Checkout;
